using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The MCP SDK discovers methods decorated with [McpServerTool] via reflection.
/// Constructor parameters are resolved from DI automatically.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool, Description("Get the current weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name, e.g. 'Seattle'")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.weatherapi.com/v1/current.json?q={Uri.EscapeDataString(city)}";

        var response = await _http.GetAsync(url, cancellationToken);
        if (!response.IsSuccessStatusCode)
        {
            return $"Error: API returned {(int)response.StatusCode} for city '{city}'.";
        }

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        var location = json.GetProperty("location").GetProperty("name").GetString();
        var tempC = json.GetProperty("current").GetProperty("temp_c").GetDouble();
        var condition = json.GetProperty("current").GetProperty("condition").GetProperty("text").GetString();

        return $"{location}: {tempC}°C, {condition}";
    }

    [McpServerTool, Description("Look up the latitude and longitude of a city.")]
    public async Task<string> GetCoordinates(
        [Description("City name to geocode")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.weatherapi.com/v1/search.json?q={Uri.EscapeDataString(city)}";

        var response = await _http.GetAsync(url, cancellationToken);
        if (!response.IsSuccessStatusCode)
        {
            return $"Error: API returned {(int)response.StatusCode}.";
        }

        var results = await response.Content.ReadFromJsonAsync<JsonElement[]>(cancellationToken);
        if (results is null || results.Length == 0)
        {
            return $"No results found for '{city}'.";
        }

        var first = results[0];
        var name = first.GetProperty("name").GetString();
        var lat = first.GetProperty("lat").GetDouble();
        var lon = first.GetProperty("lon").GetDouble();

        return $"{name}: lat={lat}, lon={lon}";
    }
}

using Microsoft.Extensions.DependencyInjection;
using ModelContextProtocol.Server;
using McpServer;

// Build the MCP server with stdio transport.
// The SDK reads JSON-RPC messages from stdin and writes responses to stdout.
var builder = McpServerApp.CreateBuilder(args);

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

// Register a named HttpClient for WeatherTools via the DI container.
// The SDK resolves constructor parameters from this container when instantiating tool classes.
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.DefaultRequestHeaders.Add("User-Agent", "McpWeatherServer/1.0");
});

var app = builder.Build();
await app.RunAsync();

